class Solution {
public:
    string addStrings(string num1, string num2) {
        int i=num1.size()-1, j=num2.size()-1, carry=0;
        string ans;
        while(i>=0||j>=0||carry){
            int d=carry;
            if(i>=0) d+=num1[i--]-'0';
            if(j>=0) d+=num2[j--]-'0';
            ans.push_back('0'+d%10); carry=d/10;
        }
        reverse(ans.begin(), ans.end());
        return ans;
    }
};

